  1→import { useState, useCallback, useRef, useMemo, useEffect } from "react";
  2→import { AnimatePresence, motion } from "framer-motion";
  3→import {
  4→  ArrowUp,
  5→  ChevronDown,
  6→  Check,
  7→  FolderOpen,
  8→  GitBranch,
  9→  Search,
 10→} from "lucide-react";
 11→import { capabilities } from "@/platform/capabilities";
 12→import { cn } from "@/shared/lib/utils";
 13→import { getAgentLogo } from "@/assets/agents";
 14→import {
 15→  getRuntimeModelLabel,
 16→  getRuntimeModelOption,
 17→  RUNTIME_MODEL_OPTIONS,
 18→  MODEL_PICKER_GROUPS,
 19→  type RuntimeAgentType,
 20→} from "@/features/session/lib/agentRuntime";
 21→import { PastedImageCard } from "@/features/session/ui/PastedImageCard";
 22→import { BranchSelector } from "@/features/workspace/ui/BranchSelector";
 23→import type { Repository } from "../types";
 24→
 25→// ── Image Support ────────────────────────────────────────────────────
 26→interface Attachment {
 27→  id: string;
 28→  file: File;
 29→  preview: string;
 30→  type: string;
 31→}
 32→
 33→const SUPPORTED_IMAGE_TYPES = new Set(["image/jpeg", "image/png", "image/gif", "image/webp"]);
 34→
 35→// ── Easing ──────────────────────────────────────────────────────────
 36→const EASE_OUT_QUART: [number, number, number, number] = [0.165, 0.84, 0.44, 1];
 37→
 38→// ── Persistence ─────────────────────────────────────────────────────
 39→const LAST_REPO_KEY = "deus:welcome-last-repo";
 40→const LAST_MODEL_KEY = "deus:welcome-last-model";
 41→
 42→function getStoredRepoId(): string | null {
 43→  try {
 44→    return localStorage.getItem(LAST_REPO_KEY);
 45→  } catch {
 46→    return null;
 47→  }
 48→}
 49→
 50→function setStoredRepoId(id: string) {
 51→  try {
 52→    localStorage.setItem(LAST_REPO_KEY, id);
 53→  } catch {
 54→    /* localStorage unavailable */
 55→  }
 56→}
 57→
 58→function getStoredModel(): string {
 59→  try {
 60→    return localStorage.getItem(LAST_MODEL_KEY) ?? "claude:sonnet";
 61→  } catch {
 62→    return "claude:sonnet";
 63→  }
 64→}
 65→
 66→function setStoredModel(model: string) {
 67→  try {
 68→    localStorage.setItem(LAST_MODEL_KEY, model);
 69→  } catch {
 70→    /* localStorage unavailable */
 71→  }
 72→}
 73→
 74→// ── Quick Prompts ───────────────────────────────────────────────────
 75→const QUICK_PROMPTS = [
 76→  "Find and fix bugs",
 77→  "Write missing tests",
 78→  "Explain this codebase",
 79→  "Clean up the code",
 80→  "Update dependencies",
 81→];
 82→
 83→// ── Types ───────────────────────────────────────────────────────────
 84→interface WelcomeViewProps {
 85→  repos: Repository[];
 86→  onSendMessage: (repoId: string, message: string, model: string, branch?: string) => void;
 87→  onOpenProject?: () => void;
 88→  onCloneRepository?: () => void;
 89→  /** True while workspace is being created after send */
 90→  sending?: boolean;
 91→}
 92→
 93→// ── Agent Logo Helper ───────────────────────────────────────────────
 94→function AgentLogo({ type, className }: { type: RuntimeAgentType; className?: string }) {
 95→  const Logo = getAgentLogo(type);
 96→  if (!Logo) {
 97→    return <span className={cn("bg-muted-foreground/80 inline-flex rounded-full", className)} />;
 98→  }
 99→  return <Logo className={cn("flex-shrink-0", className)} />;
100→}
101→
102→// ── Path Utility ────────────────────────────────────────────────────
103→function abbreviatePath(path: string): string {
104→  const home = path.match(/^\/Users\/[^/]+/)?.[0];
105→  if (home) return path.replace(home, "~");
106→  return path;
107→}
108→
109→/**
110→ * WelcomeView — "Gravity Well" input-first workspace launcher.
111→ *
112→ * Design direction: The message input is the gravitational center.
113→ * Repo picker and model selector live in a context bar at the top
114→ * of the input card. Quick prompts orbit below. The question headline
115→ * draws the eye downward into the input.
116→ *
117→ * Flow: user types message + picks repo/model -> onSendMessage()
118→ * -> parent creates workspace + session, transitions to two-panel layout.
119→ */
120→export function WelcomeView({
121→  repos,
122→  onSendMessage,
123→  onOpenProject,
124→  onCloneRepository,
125→  sending = false,
126→}: WelcomeViewProps) {
127→  const hasRepos = repos.length > 0;
128→
129→  // ── Input state ─────────────────────────────────────────────────
130→  const [message, setMessage] = useState("");
131→  const [model, setModel] = useState(getStoredModel);
132→  const [attachments, setAttachments] = useState<Attachment[]>([]);
133→  const [isDragging, setIsDragging] = useState(false);
134→  const textareaRef = useRef<HTMLTextAreaElement>(null);
135→
136→  // Process image files into attachment previews (shared by paste + drop)
137→  const processFiles = useCallback(async (files: File[]) => {
138→    const imageFiles = files.filter((f) => SUPPORTED_IMAGE_TYPES.has(f.type));
139→    if (!imageFiles.length) return;
140→    const previews = await Promise.all(
141→      imageFiles.map(
142→        (file) =>
143→          new Promise<Attachment | null>((resolve) => {
144→            const reader = new FileReader();
145→            reader.onload = (ev) =>
146→              resolve({
147→                id: crypto.randomUUID(),
148→                file,
149→                preview: ev.target?.result as string,
150→                type: file.type,
151→              });
152→            reader.onerror = () => resolve(null);
153→            reader.onabort = () => resolve(null);
154→            reader.readAsDataURL(file);
155→          })
156→      )
157→    );
158→    const valid = previews.filter(Boolean) as Attachment[];
159→    if (valid.length) setAttachments((prev) => [...prev, ...valid]);
160→  }, []);
161→
162→  const removeAttachment = useCallback((id: string) => {
163→    setAttachments((prev) => prev.filter((a) => a.id !== id));
164→  }, []);
165→
166→  const handlePaste = useCallback(
167→    (e: React.ClipboardEvent) => {
168→      const imageFiles: File[] = [];
169→      if (e.clipboardData.items) {
170→        for (const item of Array.from(e.clipboardData.items)) {
171→          if (item.kind === "file" && SUPPORTED_IMAGE_TYPES.has(item.type)) {
172→            const file = item.getAsFile();
173→            if (file) imageFiles.push(file);
174→          }
175→        }
176→      }
177→      if (imageFiles.length > 0) {
178→        e.preventDefault();
179→        processFiles(imageFiles);
180→      }
181→    },
182→    [processFiles]
183→  );
184→
185→  // Build content with images in Anthropic content blocks format
186→  const buildCombinedContent = useCallback(() => {
187→    const typed = message.trim();
188→    if (attachments.length === 0) return typed;
189→
190→    const blocks: Array<Record<string, unknown>> = [];
191→    if (typed) {
192→      blocks.push({ type: "text", text: typed });
193→    }
194→    for (const attachment of attachments) {
195→      const base64Data = attachment.preview.includes(",")
196→        ? attachment.preview.split(",")[1]
197→        : attachment.preview;
198→      blocks.push({
199→        type: "image",
200→        source: { type: "base64", media_type: attachment.type, data: base64Data },
201→      });
202→    }
203→    return JSON.stringify(blocks);
204→  }, [message, attachments]);
205→
206→  // ── Repo selection ──────────────────────────────────────────────
207→  const [selectedRepoId, setSelectedRepoId] = useState<string | null>(() => {
208→    const stored = getStoredRepoId();
209→    if (stored && repos.some((r) => r.id === stored)) return stored;
210→    return repos[0]?.id ?? null;
211→  });
212→
213→  // Re-sync when repos list changes (e.g. after adding first repo)
214→  useEffect(() => {
215→    if (!hasRepos) {
216→      setSelectedRepoId(null);
217→      return;
218→    }
219→    if (!selectedRepoId || !repos.some((r) => r.id === selectedRepoId)) {
220→      const stored = getStoredRepoId();
221→      const validStored = stored && repos.some((r) => r.id === stored);
222→      setSelectedRepoId(validStored ? stored : repos[0].id);
223→    }
224→  }, [repos, hasRepos, selectedRepoId]);
225→
226→  const selectedRepo = useMemo(
227→    () => repos.find((r) => r.id === selectedRepoId) ?? null,
228→    [repos, selectedRepoId]
229→  );
230→
231→  // ── Branch selection ──────────────────────────────────────────────
232→  const [selectedBranch, setSelectedBranch] = useState<string | null>(null);
233→  const displayBranch = selectedBranch ?? selectedRepo?.git_default_branch ?? "main";
234→
235→  // Reset branch when repo changes
236→  useEffect(() => {
237→    setSelectedBranch(null);
238→  }, [selectedRepoId]);
239→
240→  // ── Repo picker dropdown ────────────────────────────────────────
241→  const [repoPickerOpen, setRepoPickerOpen] = useState(false);
242→  const [repoFilter, setRepoFilter] = useState("");
243→  const repoPickerRef = useRef<HTMLDivElement>(null);
244→  const filterInputRef = useRef<HTMLInputElement>(null);
245→
246→  const filteredRepos = useMemo(() => {
247→    if (!repoFilter) return repos;
248→    const q = repoFilter.toLowerCase();
249→    return repos.filter((r) => r.name.toLowerCase().includes(q));
250→  }, [repos, repoFilter]);
251→
252→  // Close on outside click
253→  useEffect(() => {
254→    if (!repoPickerOpen) return;
255→    function handleClick(e: MouseEvent) {
256→      if (repoPickerRef.current && !repoPickerRef.current.contains(e.target as Node)) {
257→        setRepoPickerOpen(false);
258→        setRepoFilter("");
259→      }
260→    }
261→    document.addEventListener("mousedown", handleClick);
262→    return () => document.removeEventListener("mousedown", handleClick);
263→  }, [repoPickerOpen]);
264→
265→  // Auto-focus filter on open
266→  useEffect(() => {
267→    if (repoPickerOpen) {
268→      setTimeout(() => filterInputRef.current?.focus(), 50);
269→    } else {
270→      setRepoFilter("");
271→    }
272→  }, [repoPickerOpen]);
273→
274→  const handleSelectRepo = useCallback((repoId: string) => {
275→    setSelectedRepoId(repoId);
276→    setStoredRepoId(repoId);
277→    setRepoPickerOpen(false);
278→    setTimeout(() => textareaRef.current?.focus(), 50);
279→  }, []);
280→
281→  // ── Model picker dropdown ───────────────────────────────────────
282→  const [modelPickerOpen, setModelPickerOpen] = useState(false);
283→  const modelPickerRef = useRef<HTMLDivElement>(null);
284→
285→  useEffect(() => {
286→    if (!modelPickerOpen) return;
287→    function handleClick(e: MouseEvent) {
288→      if (modelPickerRef.current && !modelPickerRef.current.contains(e.target as Node)) {
289→        setModelPickerOpen(false);
290→      }
291→    }
292→    document.addEventListener("mousedown", handleClick);
293→    return () => document.removeEventListener("mousedown", handleClick);
294→  }, [modelPickerOpen]);
295→
296→  const modelLabel = getRuntimeModelLabel(model);
297→  const selectedModelOption = getRuntimeModelOption(model);
298→
299→  const handleSelectModel = useCallback((value: string) => {
300→    setModel(value);
301→    setStoredModel(value);
302→    setModelPickerOpen(false);
303→  }, []);
304→
305→  // ── Send ────────────────────────────────────────────────────────
306→  const hasContent = message.trim().length > 0 || attachments.length > 0;
307→  const canSend = hasContent && !!selectedRepoId && !sending;
308→
309→  const handleSend = useCallback(() => {
310→    if (!canSend || !selectedRepoId) return;
311→    const content = buildCombinedContent();
312→    if (!content) return;
313→    onSendMessage(selectedRepoId, content, model, selectedBranch ?? undefined);
314→    setAttachments([]);
315→  }, [canSend, selectedRepoId, buildCombinedContent, model, selectedBranch, onSendMessage]);
316→
317→  const handleKeyDown = useCallback(
318→    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
319→      if (
320→        e.key === "Enter" &&
321→        !e.shiftKey &&
322→        !e.metaKey &&
323→        !e.ctrlKey &&
324→        !e.nativeEvent.isComposing
325→      ) {
326→        e.preventDefault();
327→        handleSend();
328→      }
329→    },
330→    [handleSend]
331→  );
332→
333→  // Quick prompts fill the textarea — user can review/edit before sending.
334→  // This avoids accidental sends and lets users customize the prompt.
335→  const handleQuickPrompt = useCallback(
336→    (prompt: string) => {
337→      if (!selectedRepoId || sending) return;
338→      setMessage(prompt);
339→      // Focus + move cursor to end so user can append or edit
340→      setTimeout(() => {
341→        const ta = textareaRef.current;
342→        if (ta) {
343→          ta.focus();
344→          ta.style.height = "auto";
345→          ta.style.height = `${Math.min(ta.scrollHeight, 192)}px`;
346→        }
347→      }, 10);
348→    },
349→    [selectedRepoId, sending]
350→  );
351→
352→  // Auto-resize textarea
353→  const handleTextareaChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
354→    setMessage(e.target.value);
355→    const ta = e.target;
356→    ta.style.height = "auto";
357→    ta.style.height = `${Math.min(ta.scrollHeight, 192)}px`;
358→  }, []);
359→
360→  return (
361→    <div className="flex h-full min-h-0 flex-1 flex-col items-center">
362→      {/* Top spacer — pushes content to ~30% from top (natural reading zone,
363→       * not geometric center which feels lifeless on tall displays) */}
364→      <div className="flex-[0_0_30%]" />
365→
366→      {/* Label — classifies the space without competing with the input.
367→       * 14px uppercase with wide tracking (Vignelli-style section label).
368→       * The user's typed text at 14px becomes the most prominent element.
369→       * Switches from "building" to "start with a project" for zero-repo. */}
370→      <motion.h1
371→        key={hasRepos ? "has-repos" : "zero-repos"}
372→        initial={{ opacity: 0, y: 8 }}
373→        animate={{ opacity: 1, y: 0 }}
374→        transition={{ duration: 0.3, ease: EASE_OUT_QUART }}
375→        className="text-text-muted mb-5 w-full max-w-[560px] px-6 text-sm font-semibold uppercase"
376→        style={{ letterSpacing: "0.08em" }}
377→      >
378→        {hasRepos ? "What are we building?" : "Start with a project"}
379→      </motion.h1>
380→
381→      {/* Input Card — the gravitational center */}
382→      <motion.div
383→        initial={{ opacity: 0, y: 12 }}
384→        animate={{ opacity: 1, y: 0 }}
385→        transition={{ duration: 0.4, delay: 0.06, ease: EASE_OUT_QUART }}
386→        className="w-full max-w-[560px] px-6"
387→      >
388→        <div
389→          className={cn(
390→            "bg-bg-elevated border-border-subtle overflow-visible rounded-2xl border transition-[border-color,box-shadow] duration-200",
391→            "focus-within:border-border-strong focus-within:shadow-md",
392→            isDragging && "border-border-strong ring-1 ring-foreground/10"
393→          )}
394→          onDragOver={(e) => {
395→            e.preventDefault();
396→            if (!isDragging) setIsDragging(true);
397→          }}
398→          onDragLeave={() => setIsDragging(false)}
399→          onDrop={(e) => {
400→            e.preventDefault();
401→            setIsDragging(false);
402→            const files = Array.from(e.dataTransfer.files);
403→            if (files.length > 0) processFiles(files);
404→          }}
405→        >
406→          {/* Context bar — repo picker (left) + branch picker (right) */}
407→          <div className="border-border-subtle/50 flex items-center justify-between border-b px-1 py-0.5">
408→            {/* Repo picker trigger */}
409→            {hasRepos ? (
410→              <div ref={repoPickerRef} className="relative">
411→                <button
412→                  type="button"
413→                  onClick={() => setRepoPickerOpen(!repoPickerOpen)}
414→                  className="text-text-muted hover:text-text-secondary group flex items-center gap-1.5 rounded-lg px-2.5 py-1.5 text-xs transition-colors duration-150"
415→                >
416→                  {/* Green glow dot — active project indicator */}
417→                  <span className="relative flex h-1.5 w-1.5 shrink-0" aria-hidden>
418→                    <span className="absolute -inset-0.5 rounded-full bg-emerald-400/30 blur-[2px]" />
419→                    <span className="relative h-1.5 w-1.5 rounded-full bg-emerald-400" />
420→                  </span>
421→                  <span className="max-w-[200px] truncate font-medium">
422→                    {selectedRepo?.name ?? "Select repo"}
423→                  </span>
424→                  <ChevronDown
425→                    className={cn(
426→                      "text-text-disabled size-3 transition-transform duration-200",
427→                      repoPickerOpen && "rotate-180"
428→                    )}
429→                  />
430→                </button>
431→
432→                {/* Repo dropdown — opens downward from context bar */}
433→                <AnimatePresence>
434→                  {repoPickerOpen && (
435→                    <motion.div
436→                      initial={{ opacity: 0, scale: 0.96, y: -4 }}
437→                      animate={{ opacity: 1, scale: 1, y: 0 }}
438→                      exit={{ opacity: 0, scale: 0.96, y: -4 }}
439→                      transition={{ duration: 0.15, ease: [0.215, 0.61, 0.355, 1] }}
440→                      className={cn(
441→                        "absolute top-full left-0 z-50 mt-1 w-72 overflow-hidden rounded-xl border",
442→                        "border-border/55 from-bg-overlay/95 to-bg-elevated/94 bg-linear-to-b backdrop-blur-2xl",
443→                        "shadow-[var(--shadow-elevated)]"
444→                      )}
445→                    >
446→                      {/* Filter input */}
447→                      <div className="border-border-subtle flex items-center gap-2 border-b px-3 py-2">
448→                        <Search className="text-text-disabled size-3.5 shrink-0" />
449→                        <input
450→                          ref={filterInputRef}
451→                          type="text"
452→                          value={repoFilter}
453→                          onChange={(e) => setRepoFilter(e.target.value)}
454→                          placeholder="Search repos..."
455→                          className="text-text-primary placeholder:text-text-disabled w-full bg-transparent text-xs outline-none"
456→                        />
457→                      </div>
458→
459→                      {/* Repo list — virtualized scroll for 30+ repos */}
460→                      <div className="scrollbar-vibrancy max-h-[224px] overflow-y-auto py-1">
461→                        {filteredRepos.length === 0 && (
462→                          <div className="text-text-disabled px-3 py-3 text-center text-xs">
463→                            No repos match
464→                          </div>
465→                        )}
466→                        {filteredRepos.map((repo) => {
467→                          const isSelected = repo.id === selectedRepoId;
468→                          return (
469→                            <button
470→                              key={repo.id}
471→                              type="button"
472→                              onClick={() => handleSelectRepo(repo.id)}
473→                              className={cn(
474→                                "flex w-full items-center justify-between px-3 py-1.5 text-left text-xs transition-colors duration-100",
475→                                "hover:bg-bg-raised/45",
476→                                isSelected ? "text-text-primary" : "text-text-secondary"
477→                              )}
478→                            >
479→                              <div className="flex items-center gap-2 overflow-hidden">
480→                                {isSelected ? (
481→                                  <span className="relative flex h-1 w-1 shrink-0" aria-hidden>
482→                                    <span className="absolute -inset-px rounded-full bg-emerald-400/25 blur-[1.5px]" />
483→                                    <span className="relative h-1 w-1 rounded-full bg-emerald-400" />
484→                                  </span>
485→                                ) : (
486→                                  <span className="h-1.5 w-1.5 shrink-0" />
487→                                )}
488→                                <span className="truncate font-medium">{repo.name}</span>
489→                              </div>
490→                              <div className="flex items-center gap-2">
491→                                <span className="text-text-disabled max-w-[120px] truncate text-2xs">
492→                                  {abbreviatePath(repo.root_path)}
493→                                </span>
494→                                {isSelected && (
495→                                  <Check className="text-text-primary size-3 shrink-0" />
496→                                )}
497→                              </div>
498→                            </button>
499→                          );
500→                        })}
501→                      </div>
502→
503→                      {/* Add repo actions */}
504→                      <div className="border-border-subtle border-t py-1">
505→                        {capabilities.nativeFolderPicker && onOpenProject && (
506→                          <button
507→                            type="button"
508→                            onClick={() => {
509→                              setRepoPickerOpen(false);
510→                              onOpenProject();
511→                            }}
512→                            className="text-text-muted hover:text-text-secondary hover:bg-bg-raised/45 flex w-full items-center gap-2 px-3 py-1.5 text-xs transition-colors duration-100"
513→                          >
514→                            <FolderOpen className="size-3 shrink-0" />
515→                            <span>Open local...</span>
516→                          </button>
517→                        )}
518→                        {onCloneRepository && (
519→                          <button
520→                            type="button"
521→                            onClick={() => {
522→                              setRepoPickerOpen(false);
523→                              onCloneRepository();
524→                            }}
525→                            className="text-text-muted hover:text-text-secondary hover:bg-bg-raised/45 flex w-full items-center gap-2 px-3 py-1.5 text-xs transition-colors duration-100"
526→                          >
527→                            <GitBranch className="size-3 shrink-0" />
528→                            <span>Clone from GitHub</span>
529→                          </button>
530→                        )}
531→                      </div>
532→                    </motion.div>
533→                  )}
534→                </AnimatePresence>
535→              </div>
536→            ) : (
537→              /* Zero repos — "Add a project" label */
538→              <span className="text-text-muted flex items-center gap-1.5 px-2.5 py-1.5 text-xs">
539→                <FolderOpen className="size-3" />
540→                <span className="font-medium">Add a project</span>
541→              </span>
542→            )}
543→
544→            {/* Branch picker (right side) — only when repos exist */}
545→            {hasRepos && (
546→              <BranchSelector
547→                repoId={selectedRepoId}
548→                currentBranch={displayBranch}
549→                onBranchSelect={(name) => {
550→                  if (name === selectedRepo?.git_default_branch) {
551→                    setSelectedBranch(null);
552→                  } else {
553→                    setSelectedBranch(name);
554→                  }
555→                }}
556→              >
557→                <button
558→                  type="button"
559→                  className="text-text-disabled hover:text-text-muted flex items-center gap-1 rounded-lg px-2 py-1.5 text-xs transition-colors duration-150"
560→                >
561→                  <GitBranch className="size-3 shrink-0" />
562→                  <span className="max-w-[120px] truncate">{displayBranch}</span>
563→                  <ChevronDown className="size-2.5" />
564→                </button>
565→              </BranchSelector>
566→            )}
567→          </div>
568→
569→          {/* Image previews — shown above textarea when images are pasted/dropped */}
570→          <AnimatePresence>
571→            {attachments.length > 0 && (
572→              <motion.div
573→                initial={{ opacity: 0, height: 0 }}
574→                animate={{ opacity: 1, height: "auto" }}
575→                exit={{ opacity: 0, height: 0 }}
576→                transition={{ duration: 0.2, ease: EASE_OUT_QUART }}
577→                className="flex gap-2 overflow-x-auto px-3 pt-3"
578→              >
579→                <AnimatePresence mode="popLayout">
580→                  {attachments.map((attachment) => (
581→                    <PastedImageCard
582→                      key={attachment.id}
583→                      preview={attachment.preview}
584→                      fileName={attachment.file.name}
585→                      onRemove={() => removeAttachment(attachment.id)}
586→                    />
587→                  ))}
588→                </AnimatePresence>
589→              </motion.div>
590→            )}
