 31→  if (bytes < 1024) return `${bytes} B`;
 32→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
 33→  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
 34→  return `${(bytes / (1024 * 1024 * 1024)).toFixed(2)} GB`;
 35→}
