 37→interface CloneRepositoryModalProps {
 38→  show: boolean;
 39→  cloning: boolean;
 40→  error: string | null;
 41→  /** Override progress display with a custom status (e.g. "Setting up workspace...") */
 42→  statusMessage?: string | null;
 43→  onClose: () => void;
 44→  onClone: (githubUrl: string, targetPath: string) => void;
 45→  onClearError: () => void;
 46→}
 47→
 48→export function CloneRepositoryModal({
 49→  show,
 50→  cloning,
 51→  error,
 52→  statusMessage,
 53→  onClose,
 54→  onClone,
 55→  onClearError,
 56→}: CloneRepositoryModalProps) {
 57→  const reduceMotion = useReducedMotion();
 58→  const isMobile = useIsMobile();
 59→  const [githubUrl, setGithubUrl] = useState("");
 60→  const [targetPath, setTargetPath] = useState("");
 61→  const [defaultPath, setDefaultPath] = useState("");
 62→  const [progress, setProgress] = useState<GitCloneProgressEvent | null>(null);
 63→  const previousCloning = useRef(cloning);
 64→
 65→  // Resolve default destination path on mount.
 66→  // Mobile: use ~/.deus/repos (hidden, no user input needed).
 67→  // Desktop: use ~/Developer (shown in input field).
 68→  useEffect(() => {
 69→    if (!show) return;
 70→    (async () => {
 71→      try {
 72→        const home = await native.dialog.getHomeDir();
 73→        setDefaultPath(isMobile ? `${home}/.deus/repos` : `${home}/Developer`);
 74→      } catch {
 75→        setDefaultPath(isMobile ? "~/.deus/repos" : "~/Developer");
 76→      }
 77→      if (isMobile) setTargetPath("");
 78→    })();
 79→  }, [show, isMobile]);
 80→
 81→  useEffect(() => {
 82→    if (!cloning) {
 83→      // eslint-disable-next-line react-hooks/set-state-in-effect -- reset form when clone completes
 84→      setProgress(null);
 85→      return;
 86→    }
 87→
 88→    const unlisten = onEvent((event, data) => {
 89→      if (event === "git-clone-progress") {
 90→        setProgress(data as GitCloneProgressEvent);
 91→      }
 92→    });
 93→
 94→    return () => {
 95→      unlisten();
 96→    };
 97→  }, [cloning]);
 98→
 99→  useEffect(() => {
100→    if (previousCloning.current && !cloning) {
101→      // eslint-disable-next-line react-hooks/set-state-in-effect -- reset form after clone transition
102→      setGithubUrl("");
103→
104→      setTargetPath("");
105→    }
106→    previousCloning.current = cloning;
107→  }, [cloning]);
108→
109→  const handleClone = () => {
110→    if (!githubUrl.trim()) {
111→      return;
112→    }
113→    onClearError();
114→    // On mobile, pass the default path since the destination input is hidden.
115→    const effectivePath = isMobile ? defaultPath : targetPath.trim();
116→    onClone(githubUrl.trim(), effectivePath);
117→  };
118→
119→  const handleUrlChange = (value: string) => {
120→    setGithubUrl(value);
121→    if (error) onClearError();
