  1→/**
  2→ * Repository Actions Hook — repo registration, workspace creation, and git clone.
  3→ *
  4→ * Extracted from MainLayout to keep the layout component focused on
  5→ * orchestrating sidebar/content panels and mounting modals.
  6→ *
  7→ * Owns all state and logic for:
  8→ * - Opening a local project (native dialog + addRepo + auto-create workspace)
  9→ * - Cloning a GitHub repo (validate URL, git clone, register, create workspace)
 10→ * - Creating workspaces from the new-workspace modal
 11→ * - 409 conflict handling when registering a repo that already exists
 12→ * - Generation counter to prevent stale clone invocations from mutating state
 13→ */
 14→
 15→import { useState, useRef, useCallback } from "react";
 16→import { toast } from "sonner";
 17→import type { Repository } from "@/features/repository/types";
 18→import { useCreateWorkspace } from "@/features/workspace/api";
 19→import { useAddRepo } from "@/features/repository/api";
 20→import { useSidebarStore } from "@/features/sidebar/store";
 21→import { native } from "@/platform";
 22→import { capabilities } from "@/platform/capabilities";
 23→import { getBackendUrl } from "@/shared/config/api.config";
 24→import { extractRepoNameFromUrl } from "@/shared/lib/utils";
 25→import { getErrorMessage } from "@shared/lib/errors";
 26→
 27→interface UseRepoActionsOptions {
 28→  selectWorkspace: (id: string | null) => void;
 29→  openNewWorkspaceModal: () => void;
 30→  closeNewWorkspaceModal: () => void;
 31→}
 32→
 33→export function useRepoActions({
 34→  selectWorkspace,
 35→  openNewWorkspaceModal,
 36→  closeNewWorkspaceModal,
 37→}: UseRepoActionsOptions) {
 38→  // Mutations
 39→  const createWorkspaceMutation = useCreateWorkspace();
 40→  const addRepoMutation = useAddRepo();
 41→  const expandRepo = useSidebarStore((s) => s.expandRepo);
 42→
 43→  // New-workspace modal state
 44→  const [selectedRepoId, setSelectedRepoId] = useState("");
 45→  const [creating, setCreating] = useState(false);
 46→
 47→  // Clone modal state
 48→  const [cloning, setCloning] = useState(false);
 49→  const [showCloneModal, setShowCloneModal] = useState(false);
 50→  const [cloneError, setCloneError] = useState<string | null>(null);
 51→  const [cloneStatus, setCloneStatus] = useState<string | null>(null);
 52→
 53→  // Generation counter: prevents stale clone invocations from mutating state.
 54→  // Each call to handleCloneRepository captures its generation; if the counter
 55→  // advances (via close or a new clone), earlier invocations bail out.
 56→  const cloneGenerationRef = useRef(0);
 57→
 58→  /** Reset all clone modal state to idle. */
 59→  function resetCloneState() {
 60→    setShowCloneModal(false);
 61→    setCloneError(null);
 62→    setCloneStatus(null);
 63→    setCloning(false);
 64→  }
 65→
 66→  /** Add a repo, falling back to the existing one on 409 conflict. */
 67→  async function addRepoOrUseExisting(path: string): Promise<Repository> {
 68→    try {
 69→      return await addRepoMutation.mutateAsync(path);
 70→    } catch (err) {
 71→      const addError = err as { status?: number; details?: { details?: Repository } };
 72→      const existingRepo = addError?.details?.details;
 73→      if (addError?.status === 409 && existingRepo?.id) {
 74→        return existingRepo;
 75→      }
 76→      throw err;
 77→    }
 78→  }
 79→
 80→  /** Create a workspace for the given repo and select it. */
 81→  const createAndSelectWorkspace = useCallback(
 82→    async (repoId: string) => {
 83→      setCreating(true);
 84→      try {
 85→        const workspace = await createWorkspaceMutation.mutateAsync(repoId);
 86→        selectWorkspace(workspace.id);
 87→        expandRepo(workspace.repository_id);
 88→      } catch (error) {
 89→        selectWorkspace(null);
 90→        console.error("Error creating workspace:", error);
 91→        toast.error(getErrorMessage(error));
 92→      } finally {
 93→        setCreating(false);
 94→      }
 95→    },
 96→    [createWorkspaceMutation, selectWorkspace, expandRepo]
 97→  );
 98→
 99→  /** Create workspace from the new-workspace modal (validates repo selection). */
100→  async function createWorkspaceFromModal() {
101→    if (!selectedRepoId) {
102→      toast.error("Please select a repository");
103→      return;
104→    }
105→    const repoIdToCreate = selectedRepoId;
106→    setSelectedRepoId("");
107→    closeNewWorkspaceModal();
108→    await createAndSelectWorkspace(repoIdToCreate);
109→  }
110→
111→  /** Handle "New Workspace" — if repoId is provided, create directly; otherwise open modal. */
112→  const handleNewWorkspace = useCallback(
113→    async (repoId?: string) => {
114→      if (repoId) {
115→        await createAndSelectWorkspace(repoId);
116→        return;
117→      }
118→      openNewWorkspaceModal();
119→    },
120→    [openNewWorkspaceModal, createAndSelectWorkspace]
121→  );
122→
123→  /** Open a local project via native file dialog. */
124→  async function handleOpenProject() {
125→    if (!capabilities.nativeFolderPicker) return;
126→    const folderPath = await native.dialog.pickFolder();
127→    if (!folderPath) return;
128→    const folderName = folderPath.split("/").pop() || folderPath;
129→    const toastId = toast.loading(`Adding "${folderName}"…`);
130→
131→    try {
132→      const repo = await addRepoOrUseExisting(folderPath);
133→      const workspace = await createWorkspaceMutation.mutateAsync(repo.id);
134→      selectWorkspace(workspace.id);
135→      expandRepo(workspace.repository_id);
136→      toast.success(`"${repo.name}" ready`, { id: toastId });
137→    } catch (error) {
138→      console.error("Error adding repository:", error);
139→      toast.error(getErrorMessage(error), { id: toastId });
140→    }
141→  }
142→
143→  /** Clone a GitHub repository with staleness detection. */
144→  async function handleCloneRepository(githubUrl: string, targetPath: string) {
145→    // Advance generation so any in-flight clone from a previous invocation bails out.
146→    const generation = ++cloneGenerationRef.current;
147→    const isStale = () => generation !== cloneGenerationRef.current;
148→
149→    setCloning(true);
150→    setCloneError(null);
151→    setCloneStatus(null);
152→    try {
153→      const repoName = extractRepoNameFromUrl(githubUrl);
154→      if (!repoName) {
155→        setCloneError("Invalid repository URL");
156→        setCloning(false);
157→        return;
158→      }
159→
160→      let cloneTarget = targetPath;
161→      if (!cloneTarget) {
162→        // Default to ~/Developer/<repoName>
163→        const home = await native.dialog.getHomeDir();
164→        cloneTarget = `${home}/Developer/${repoName}`;
165→      } else if (!targetPath.endsWith(repoName) && !targetPath.endsWith(`${repoName}/`)) {
166→        cloneTarget = `${targetPath}/${repoName}`;
167→      }
168→
169→      // Phase 1: Git clone via backend HTTP (progress events pushed via WS)
170→      const baseUrl = await getBackendUrl();
171→      const cloneRes = await fetch(`${baseUrl}/api/repos/clone`, {
172→        method: "POST",
173→        headers: { "Content-Type": "application/json" },
174→        body: JSON.stringify({ url: githubUrl, targetPath: cloneTarget }),
175→      });
176→      if (!cloneRes.ok) {
177→        const err = await cloneRes.json().catch(() => ({ error: "Clone failed" }));
178→        throw new Error(err.error || `HTTP ${cloneRes.status}`);
179→      }
180→      if (isStale()) return;
181→
182→      // Phase 2: Register repository
183→      setCloneStatus("Adding repository...");
184→      const repo = await addRepoOrUseExisting(cloneTarget);
185→      if (isStale()) return;
186→
187→      // Phase 3: Create workspace (returns immediately as 'initializing')
188→      setCloneStatus("Setting up workspace...");
189→      const workspace = await createWorkspaceMutation.mutateAsync(repo.id);
190→      if (isStale()) return;
191→
192→      // Close modal and select workspace immediately — workspace state transitions
193→      // are pushed via WORKSPACE_PROGRESS events which invalidate React Query.
194→      resetCloneState();
195→      selectWorkspace(workspace.id);
196→      expandRepo(workspace.repository_id);
197→      toast.success(`"${repo.name}" cloned`);
198→    } catch (error) {
199→      if (!isStale()) {
200→        console.error("Error cloning repository:", error);
201→        setCloneError(getErrorMessage(error));
202→        setCloneStatus(null);
203→      }
204→    } finally {
205→      if (!isStale()) {
206→        setCloning(false);
207→      }
208→    }
209→  }
210→
211→  /** Close clone modal and cancel any in-flight clone. */
212→  const closeCloneModal = useCallback(() => {
213→    cloneGenerationRef.current++;
214→    resetCloneState();
215→  }, []);
216→
217→  /** Create workspace from a GitHub PR or branch (extended params). */
218→  const handleNewWorkspaceFromGitHub = useCallback(
219→    async (params: {
220→      repositoryId: string;
221→      source_branch: string;
222→      pr_number?: number;
223→      pr_url?: string;
224→      pr_title?: string;
225→      target_branch?: string;
226→    }) => {
227→      setCreating(true);
228→      try {
229→        const workspace = await createWorkspaceMutation.mutateAsync(params);
230→        selectWorkspace(workspace.id);
231→        expandRepo(workspace.repository_id);
232→      } catch (error) {
233→        selectWorkspace(null);
234→        console.error("Failed to create workspace from GitHub:", error);
235→        toast.error(getErrorMessage(error));
236→      } finally {
237→        setCreating(false);
238→      }
239→    },
240→    [createWorkspaceMutation, selectWorkspace, expandRepo]
241→  );
242→
243→  return {
244→    // New-workspace modal state
245→    selectedRepoId,
246→    setSelectedRepoId,
247→    creating,
248→    createWorkspaceFromModal,
249→    handleNewWorkspace,
250→    handleNewWorkspaceFromGitHub,
251→
252→    // Clone modal state
253→    showCloneModal,
254→    setShowCloneModal,
255→    cloning,
256→    cloneError,
257→    cloneStatus,
258→    closeCloneModal,
259→    handleCloneRepository,
260→
