// ─── Clone Endpoint ──────────────────────────────────────────

/** Broadcast a clone progress q:event to all connected WS clients. */
function pushCloneProgress(data: GitCloneProgressEvent): void {
  broadcast(JSON.stringify({ type: "q:event", event: "git-clone-progress", data }));
}

/**
 * Parse git clone --progress stderr output into structured progress.
 * Git writes progress like:
 *   Receiving objects:  42% (1234/2938), 5.12 MiB | 2.00 MiB/s
 *   Resolving deltas:  67% (890/1328)
 */
function parseGitProgress(line: string): Partial<GitCloneProgressEvent> | null {
  // Match: "Phase:  XX% (received/total), size" or "Phase:  XX% (received/total)"
  const match = line.match(
    /^(Receiving objects|Resolving deltas|Counting objects|Compressing objects|Enumerating objects):\s+(\d+)%\s+\((\d+)\/(\d+)\)(?:,\s+([\d.]+)\s+(\w+))?/
  );
  if (!match) return null;

  const phaseStr = match[1];
  const percent = parseInt(match[2], 10);
  const received = parseInt(match[3], 10);
  const total = parseInt(match[4], 10);
  const sizeValue = match[5] ? parseFloat(match[5]) : 0;
  const sizeUnit = match[6] || "";

  let received_bytes = 0;
  if (sizeValue > 0) {
    const multipliers: Record<string, number> = {
      B: 1,
      KiB: 1024,
      MiB: 1024 * 1024,
      GiB: 1024 * 1024 * 1024,
      KB: 1000,
      MB: 1000000,
      GB: 1000000000,
    };
    received_bytes = Math.round(sizeValue * (multipliers[sizeUnit] || 1));
  }

  let phase: GitCloneProgressEvent["phase"] = "receiving";
  if (phaseStr === "Resolving deltas") phase = "resolving";
  else if (phaseStr === "Counting objects" || phaseStr === "Enumerating objects") phase = "connecting";
  else if (phaseStr === "Compressing objects") phase = "indexing";

  return { percent, received, total, received_bytes, phase, status: line.trim() };
}

app.post("/repos/clone", async (c) => {
  const body = await c.req.json();
  const { url, targetPath } = body as { url: string; targetPath: string };

  if (!url || typeof url !== "string") {
    throw new ValidationError("Missing or invalid 'url' parameter");
  }
  if (!targetPath || typeof targetPath !== "string") {
    throw new ValidationError("Missing or invalid 'targetPath' parameter");
  }

  // Ensure parent directory exists
  const parentDir = path.dirname(targetPath);
  try {
    fs.mkdirSync(parentDir, { recursive: true });
  } catch (err) {
    throw new AppError(500, `Cannot create parent directory: ${(err as Error).message}`);
  }

  // Check target doesn't already exist
  if (fs.existsSync(targetPath)) {
    throw new ConflictError("Target directory already exists");
  }

  // Emit initial connecting status
  pushCloneProgress({
    percent: 0,
    received: 0,
    total: 0,
    received_bytes: 0,
    status: "Connecting...",
    phase: "connecting",
  });

  // Run git clone with progress
  return new Promise<Response>((resolve) => {
    const proc = spawn("git", ["clone", "--progress", url, targetPath], {
      stdio: ["ignore", "pipe", "pipe"],
      timeout: 300_000, // 5 minute timeout
    });

    let stderrBuffer = "";

    proc.stderr?.on("data", (chunk: Buffer) => {
      stderrBuffer += chunk.toString();
      // Git progress uses \r for line updates within a phase
      const lines = stderrBuffer.split(/[\r\n]+/);
      stderrBuffer = lines.pop() || "";

      for (const line of lines) {
        const progress = parseGitProgress(line);
        if (progress) {
          pushCloneProgress({
            percent: progress.percent ?? 0,
            received: progress.received ?? 0,
            total: progress.total ?? 0,
            received_bytes: progress.received_bytes ?? 0,
            status: progress.status ?? "Cloning...",
            phase: progress.phase ?? "receiving",
          });
        }
      }
    });

    proc.on("close", (code) => {
      if (code === 0) {
        pushCloneProgress({
          percent: 100,
          received: 0,
          total: 0,
          received_bytes: 0,
          status: "Complete",
          phase: "complete",
        });
        resolve(c.json({ success: true, path: targetPath }));
      } else {
        // Extract useful error from stderr
        const errorMsg = stderrBuffer.trim() || `git clone exited with code ${code}`;
        resolve(c.json({ error: errorMsg }, 500));
      }
    });

    proc.on("error", (err) => {
      resolve(c.json({ error: `Failed to start git: ${err.message}` }, 500));
    });
  });
});

// ─── Manifest Endpoints (per-repo, settings UI) ─────────────

