118→// ─── Clone Endpoint ──────────────────────────────────────────
119→
120→/** Broadcast a clone progress q:event to all connected WS clients. */
121→function pushCloneProgress(data: GitCloneProgressEvent): void {
122→  broadcast(JSON.stringify({ type: "q:event", event: "git-clone-progress", data }));
123→}
124→
125→/**
126→ * Parse git clone --progress stderr output into structured progress.
127→ * Git writes progress like:
128→ *   Receiving objects:  42% (1234/2938), 5.12 MiB | 2.00 MiB/s
129→ *   Resolving deltas:  67% (890/1328)
130→ */
131→function parseGitProgress(line: string): Partial<GitCloneProgressEvent> | null {
132→  // Match: "Phase:  XX% (received/total), size" or "Phase:  XX% (received/total)"
133→  const match = line.match(
134→    /^(Receiving objects|Resolving deltas|Counting objects|Compressing objects|Enumerating objects):\s+(\d+)%\s+\((\d+)\/(\d+)\)(?:,\s+([\d.]+)\s+(\w+))?/
135→  );
136→  if (!match) return null;
137→
138→  const phaseStr = match[1];
139→  const percent = parseInt(match[2], 10);
140→  const received = parseInt(match[3], 10);
141→  const total = parseInt(match[4], 10);
142→  const sizeValue = match[5] ? parseFloat(match[5]) : 0;
143→  const sizeUnit = match[6] || "";
144→
145→  let received_bytes = 0;
146→  if (sizeValue > 0) {
147→    const multipliers: Record<string, number> = {
148→      B: 1,
149→      KiB: 1024,
150→      MiB: 1024 * 1024,
151→      GiB: 1024 * 1024 * 1024,
152→      KB: 1000,
153→      MB: 1000000,
154→      GB: 1000000000,
155→    };
156→    received_bytes = Math.round(sizeValue * (multipliers[sizeUnit] || 1));
157→  }
158→
159→  let phase: GitCloneProgressEvent["phase"] = "receiving";
160→  if (phaseStr === "Resolving deltas") phase = "resolving";
161→  else if (phaseStr === "Counting objects" || phaseStr === "Enumerating objects") phase = "connecting";
162→  else if (phaseStr === "Compressing objects") phase = "indexing";
163→
164→  return { percent, received, total, received_bytes, phase, status: line.trim() };
165→}
166→
167→app.post("/repos/clone", async (c) => {
168→  const body = await c.req.json();
169→  const { url, targetPath } = body as { url: string; targetPath: string };
170→
171→  if (!url || typeof url !== "string") {
172→    throw new ValidationError("Missing or invalid 'url' parameter");
173→  }
174→  if (!targetPath || typeof targetPath !== "string") {
175→    throw new ValidationError("Missing or invalid 'targetPath' parameter");
176→  }
177→
178→  // Ensure parent directory exists
179→  const parentDir = path.dirname(targetPath);
180→  try {
181→    fs.mkdirSync(parentDir, { recursive: true });
182→  } catch (err) {
183→    throw new AppError(500, `Cannot create parent directory: ${(err as Error).message}`);
184→  }
185→
186→  // Check target doesn't already exist
187→  if (fs.existsSync(targetPath)) {
188→    throw new ConflictError("Target directory already exists");
189→  }
190→
191→  // Emit initial connecting status
192→  pushCloneProgress({
193→    percent: 0,
194→    received: 0,
195→    total: 0,
196→    received_bytes: 0,
197→    status: "Connecting...",
198→    phase: "connecting",
199→  });
200→
201→  // Run git clone with progress
202→  return new Promise<Response>((resolve) => {
203→    const proc = spawn("git", ["clone", "--progress", url, targetPath], {
204→      stdio: ["ignore", "pipe", "pipe"],
205→      timeout: 300_000, // 5 minute timeout
206→    });
207→
208→    let stderrBuffer = "";
209→
210→    proc.stderr?.on("data", (chunk: Buffer) => {
211→      stderrBuffer += chunk.toString();
212→      // Git progress uses \r for line updates within a phase
213→      const lines = stderrBuffer.split(/[\r\n]+/);
214→      stderrBuffer = lines.pop() || "";
215→
216→      for (const line of lines) {
217→        const progress = parseGitProgress(line);
218→        if (progress) {
219→          pushCloneProgress({
220→            percent: progress.percent ?? 0,
221→            received: progress.received ?? 0,
222→            total: progress.total ?? 0,
223→            received_bytes: progress.received_bytes ?? 0,
224→            status: progress.status ?? "Cloning...",
225→            phase: progress.phase ?? "receiving",
226→          });
227→        }
228→      }
229→    });
230→
231→    proc.on("close", (code) => {
232→      if (code === 0) {
233→        pushCloneProgress({
234→          percent: 100,
235→          received: 0,
236→          total: 0,
237→          received_bytes: 0,
238→          status: "Complete",
239→          phase: "complete",
240→        });
241→        resolve(c.json({ success: true, path: targetPath }));
242→      } else {
243→        // Extract useful error from stderr
244→        const errorMsg = stderrBuffer.trim() || `git clone exited with code ${code}`;
245→        resolve(c.json({ error: errorMsg }, 500));
246→      }
247→    });

