  try {
    root_path = execFileSync("git", ["rev-parse", "--show-toplevel"], {
      cwd: root_path,
      timeout: 2000,
    })
      .toString()
      .trim();
  } catch {
    throw new ValidationError("Path is not a git repository");
  }

  const repoName = path.basename(root_path);
