// ─── Clone Endpoint ──────────────────────────────────────────

/** Broadcast a clone progress q:event to all connected WS clients. */
function pushCloneProgress(data: GitCloneProgressEvent): void {
  broadcast(JSON.stringify({ type: "q:event", event: "git-clone-progress", data }));
}

/**
 * Parse git clone --progress stderr output into structured progress.
 * Git writes progress like:
 *   Receiving objects:  42% (1234/2938), 5.12 MiB | 2.00 MiB/s
 *   Resolving deltas:  67% (890/1328)
 */
function parseGitProgress(line: string): Partial<GitCloneProgressEvent> | null {
  // Match: "Phase:  XX% (received/total), size" or "Phase:  XX% (received/total)"
  const match = line.match(
    /^(Receiving objects|Resolving deltas|Counting objects|Compressing objects|Enumerating objects):\s+(\d+)%\s+\((\d+)\/(\d+)\)(?:,\s+([\d.]+)\s+(\w+))?/
  );
  if (!match) return null;

  const phaseStr = match[1];
  const percent = parseInt(match[2], 10);
  const received = parseInt(match[3], 10);
  const total = parseInt(match[4], 10);
  const sizeValue = match[5] ? parseFloat(match[5]) : 0;
  const sizeUnit = match[6] || "";

  let received_bytes = 0;
  if (sizeValue > 0) {
    const multipliers: Record<string, number> = {
      B: 1,
      KiB: 1024,
      MiB: 1024 * 1024,
      GiB: 1024 * 1024 * 1024,
      KB: 1000,
      MB: 1000000,
      GB: 1000000000,
    };
    received_bytes = Math.round(sizeValue * (multipliers[sizeUnit] || 1));
  }

  let phase: GitCloneProgressEvent["phase"] = "receiving";
  if (phaseStr === "Resolving deltas") phase = "resolving";
  else if (phaseStr === "Counting objects" || phaseStr === "Enumerating objects") phase = "connecting";
  else if (phaseStr === "Compressing objects") phase = "indexing";

  return { percent, received, total, received_bytes, phase, status: line.trim() };
}

