 1→/**
 2→ * Repository Service
 3→ *
 4→ * All data operations go through the WebSocket q:* protocol.
 5→ * One-shot reads use sendRequest, mutations use sendMutate.
 6→ */
 7→
 8→import { sendRequest, sendMutate } from "@/platform/ws";
 9→import type { Repository, Stats } from "../types";
10→import type { ManifestResponse } from "@shared/types/manifest";
11→
12→export const RepoService = {
13→  /**
14→   * Fetch all repositories
15→   */
16→  fetchAll: async (): Promise<Repository[]> => {
17→    return sendRequest<Repository[]>("repos");
18→  },
19→
20→  /**
21→   * Fetch repository by ID
22→   * Note: No dedicated request resource for single repo, but "repos" returns all.
23→   * For now, fetch all and filter. If performance matters, add a "repo" resource.
24→   */
25→  fetchById: async (id: string): Promise<Repository> => {
26→    const repos = await sendRequest<Repository[]>("repos");
27→    const repo = repos.find((r) => r.id === id);
28→    if (!repo) throw new Error(`Repository not found: ${id}`);
29→    return repo;
30→  },
31→
32→  /**
33→   * Fetch system statistics.
34→   */
35→  fetchStats: async (): Promise<Stats> => {
36→    return sendRequest<Stats>("stats");
37→  },
38→
39→  /**
40→   * Add a new repository
