139→ * Get the base URL for API requests (async).
140→ * Throws in relay mode — HTTP is tunneled over WS via client.ts bridge.
141→ */
142→export async function getBaseURL(): Promise<string> {
143→  // Lazy import to avoid circular dependency
144→  const { isRelayMode } = await import("./backend.config");
145→  if (isRelayMode()) {
