      toast.error(getErrorMessage(error), { id: toastId });
    }
  }

  /**
   * Clone a GitHub repository with staleness detection.
   * Entire flow uses HTTP to avoid WS disconnection failures.
   */
  async function handleCloneRepository(githubUrl: string, targetPath: string) {
    // Advance generation so any in-flight clone from a previous invocation bails out.
    const generation = ++cloneGenerationRef.current;
    const isStale = () => generation !== cloneGenerationRef.current;

    setCloning(true);
    setCloneError(null);
    setCloneStatus(null);
    try {
      const repoName = extractRepoNameFromUrl(githubUrl);
      if (!repoName) {
        setCloneError("Invalid repository URL");
        setCloning(false);
        return;
      }

      let cloneTarget = targetPath;
      if (!cloneTarget) {
        // Default to ~/Developer/<repoName>
        const home = await native.dialog.getHomeDir();
        cloneTarget = `${home}/Developer/${repoName}`;
      } else if (!targetPath.endsWith(repoName) && !targetPath.endsWith(`${repoName}/`)) {
        cloneTarget = `${targetPath}/${repoName}`;
      }

      const baseUrl = await getBackendUrl();
      const jsonHeaders = { "Content-Type": "application/json" };

      // Phase 1: Git clone via HTTP (progress events pushed via WS if connected)
      const cloneRes = await fetch(`${baseUrl}/api/repos/clone`, {
        method: "POST",
        headers: jsonHeaders,
        body: JSON.stringify({ url: githubUrl, targetPath: cloneTarget }),
      });
      if (!cloneRes.ok) {
        const err = await cloneRes.json().catch(() => ({ error: "Clone failed" }));
        throw new Error(err.error || `HTTP ${cloneRes.status}`);
      }
      if (isStale()) return;

      // Phase 2: Register repository via HTTP (not WS — avoids disconnection failures)
      setCloneStatus("Adding repository...");
      let repo: Repository;
      const addRes = await fetch(`${baseUrl}/api/repos`, {
        method: "POST",
        headers: jsonHeaders,
        body: JSON.stringify({ root_path: cloneTarget }),
      });
      if (addRes.status === 409) {
        // Already exists — response: { error: "...", details: <repo> }
        const conflict = await addRes.json();
        repo = conflict.details;
      } else if (addRes.ok) {
        repo = await addRes.json();
      } else {
        const err = await addRes.json().catch(() => ({ error: "Failed to add repository" }));
        throw new Error(err.error || `HTTP ${addRes.status}`);
      }
      if (isStale()) return;

      // Phase 3: Create workspace via HTTP (not WS)
      setCloneStatus("Setting up workspace...");
      const wsRes = await fetch(`${baseUrl}/api/workspaces`, {
        method: "POST",
        headers: jsonHeaders,
        body: JSON.stringify({ repository_id: repo.id }),
      });
      if (!wsRes.ok) {
        const err = await wsRes.json().catch(() => ({ error: "Failed to create workspace" }));
        throw new Error(err.error || `HTTP ${wsRes.status}`);
      }
      const workspace = await wsRes.json();
      if (isStale()) return;

      // Close modal and select workspace
      resetCloneState();
      selectWorkspace(workspace.id);
      expandRepo(workspace.repository_id);
      toast.success(`"${repo.name}" cloned`);
    } catch (error) {
      if (!isStale()) {
        console.error("Error cloning repository:", error);
        setCloneError(getErrorMessage(error));
        setCloneStatus(null);
      }
    } finally {
      if (!isStale()) {
        setCloning(false);
      }
    }
  }

  /** Close clone modal and cancel any in-flight clone. */
  const closeCloneModal = useCallback(() => {
    cloneGenerationRef.current++;
    resetCloneState();
  }, []);

  /** Create workspace from a GitHub PR or branch (extended params). */
  const handleNewWorkspaceFromGitHub = useCallback(
    async (params: {
      repositoryId: string;
      source_branch: string;
      pr_number?: number;
      pr_url?: string;
      pr_title?: string;
      target_branch?: string;
    }) => {
      setCreating(true);
      try {
        const workspace = await createWorkspaceMutation.mutateAsync(params);
        selectWorkspace(workspace.id);
        expandRepo(workspace.repository_id);
      } catch (error) {
        selectWorkspace(null);
        console.error("Failed to create workspace from GitHub:", error);
        toast.error(getErrorMessage(error));
      } finally {
        setCreating(false);
      }
    },
    [createWorkspaceMutation, selectWorkspace, expandRepo]
  );

  return {
    // New-workspace modal state
    selectedRepoId,
    setSelectedRepoId,
    creating,
    createWorkspaceFromModal,
    handleNewWorkspace,
    handleNewWorkspaceFromGitHub,

    // Clone modal state
    showCloneModal,
    setShowCloneModal,
    cloning,
    cloneError,
    cloneStatus,
    closeCloneModal,
    handleCloneRepository,

    // Open project (native dialog)
    handleOpenProject,

    // For clearing clone errors from the modal
    clearCloneError: () => setCloneError(null),
  };
}

